class Solution {
    public String smallestNumber(String pattern) {
        StringBuilder sb = new StringBuilder();
        int[] digits = new int[9];
        for (int i = 0; i < 9; i++) {
            digits[i] = i + 1;
        }
        int i = 0;
        while (i < pattern.length()) {
            if (pattern.charAt(i) == 'I') {
                sb.append(digits[0]);
                digits[0] = digits[1];
                for (int j = 1; j < 9; j++) {
                    digits[j] = digits[j + 1];
                }
            } else {
                sb.append(digits[8]);
                digits[8] = digits[7];
                for (int j = 7; j > 0; j--) {
                    digits[j] = digits[j - 1];
                }
            }
            i++;
        }
        return sb.toString();
    }
}
